import pytest
import requests

BASE_URL = "http://hr-app/api"

@pytest.mark.parametrize("role,authenticated,module_on,expected_status", [
    ("manager",  True,  True,  (200, 201)),
    ("employee", True,  True,  (403,)),
    (None,       False, True,  (401,)),
    ("manager",  True,  False, (403, 404)),
])
def test_decision_table_role_auth_module_combinations(
    role, authenticated, module_on, expected_status
):
    <set_team_module_enabled>(enabled=module_on)
    team_id = <get_existing_team_id>()
    if authenticated and role:
        token = <get_auth_token>(role=role)
        headers = {"Authorization": f"Bearer {token}"}
    else:
        headers = {}

    resp = requests.get(f"{BASE_URL}/teams/{team_id}", headers=headers)

    assert resp.status_code in expected_status, (
        f"role={role} auth={authenticated} module={module_on}: "
        f"expected one of {expected_status}, got {resp.status_code}"
    )
    <set_team_module_enabled>(enabled=True)
